func autocompleteClass(prop AutocompleteProp) string {
	var sb strings.Builder
	sb.WriteString("autocomplete")
	if prop.Disabled {
		sb.WriteString(" autocomplete--disabled")
	}
	if prop.Class != "" {
		sb.WriteString(" ")
		sb.WriteString(prop.Class)
	}
	return sb.String()
}

// autocompleteUniqueId generates a unique ID suffix or returns the provided ID.
func autocompleteUniqueId(id string) string {
	if id != "" {
		return id
	}
	return fmt.Sprintf("ac%d", autocompleteIdCounter.Add(1))
}

// inlineAutocompleteData generates the Alpine.js data initialization string.
func inlineAutocompleteData(prop AutocompleteProp, uid string) string {
	optionsJSON := optionsToJSON(prop.Options)
	searchInit := escapeJSString(prop.Value)

	return fmt.Sprintf("autocomplete({ initialValue: '%s', options: %s })", searchInit, optionsJSON)
}

// optionsToJSON converts options to JSON using encoding/json for safety.
func optionsToJSON(options []AutocompleteOption) string {
	if len(options) == 0 {
		return "[]"
	}
	data, err := json.Marshal(options)
	if err != nil {
		return "[]"
	}
	return string(data)
}

// escapeJSString escapes a string for use in JavaScript single-quoted strings.
func escapeJSString(s string) string {
	s = strings.ReplaceAll(s, "\\", "\\\\")
	s = strings.ReplaceAll(s, "'", "\\'")
	s = strings.ReplaceAll(s, "\n", "\\n")
	s = strings.ReplaceAll(s, "\r", "\\r")
	return s
}

